const all = $input.all();
const items = [];
const cutoff72h = Date.now() - 72*60*60*1000;
const seen = new Set();

for (const inputItem of all) {
  const xml = inputItem.json.data || inputItem.json.body || inputItem.json;
  const raw = typeof xml === 'string' ? xml : JSON.stringify(xml);
  const itemRegex = /<item[\s\S]*?<\/item>/g;
  const matches = raw.match(itemRegex) || [];
  for (const block of matches) {
    const grab = (tag) => {
      const m = block.match(new RegExp('<'+tag+'(?:[^>]*)>([\\s\\S]*?)<\\/'+tag+'>'));
      if (!m) return '';
      return m[1].replace(/<!\[CDATA\[/g,'').replace(/\]\]>/g,'').replace(/<[^>]+>/g,'').trim();
    };
    const title = grab('title');
    const link = grab('link');
    const pubDate = grab('pubDate');
    const description = grab('description');
    if (!title) continue;
    const ts = pubDate ? Date.parse(pubDate) : NaN;
    // Use 72h window; if pubDate missing treat as fresh
    if (!isNaN(ts) && ts < cutoff72h) continue;
    const key = title.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    items.push({title, link, pubDate, summary: description.slice(0,400)});
  }
}

// Fallback: if still empty, parse all items ignoring date (last 10 per feed)
if (items.length === 0) {
  const seen2 = new Set();
  for (const inputItem of all) {
    const xml = inputItem.json.data || inputItem.json.body || inputItem.json;
    const raw = typeof xml === 'string' ? xml : JSON.stringify(xml);
    const itemRegex = /<item[\s\S]*?<\/item>/g;
    const matches = raw.match(itemRegex) || [];
    let feedCount = 0;
    for (const block of matches) {
      if (feedCount >= 5) break;
      const grab = (tag) => {
        const m = block.match(new RegExp('<'+tag+'(?:[^>]*)>([\\s\\S]*?)<\\/'+tag+'>'));
        if (!m) return '';
        return m[1].replace(/<!\[CDATA\[/g,'').replace(/\]\]>/g,'').replace(/<[^>]+>/g,'').trim();
      };
      const title = grab('title');
      const link = grab('link');
      const pubDate = grab('pubDate');
      const description = grab('description');
      if (!title) continue;
      const key = title.toLowerCase();
      if (seen2.has(key)) continue;
      seen2.add(key);
      items.push({title, link, pubDate, summary: description.slice(0,400)});
      feedCount++;
    }
  }
}

return [{json:{count: items.length, items}}];

const raw = $input.first().json;
let opps = [];
try {
  const data = typeof raw === 'string' ? JSON.parse(raw) : raw;
  const list = data.opportunitiesData || data.items || [];
  opps = list.slice(0,8).map(o => ({
    title: o.title || o.opportunityTitle || '',
    agency: o.departmentName || o.organizationHierarchy?.[0]?.name || '',
    naics: o.naicsCode || '',
    type: o.type || '',
    postedDate: o.postedDate || '',
    responseDeadline: o.responseDeadLine || '',
    solicitationNumber: o.solicitationNumber || '',
    link: o.uiLink || ('https://sam.gov/opp/'+o.noticeId)
  }));
} catch(e) { opps = []; }
return [{json:{sam_count: opps.length, sam_opps: opps}}];

const rss = $('Parse RSS Filter 24h').first().json;
const sam = $('Parse SAM Opps').first().json;
let perp = '';
try { perp = $('Fetch Perplexity Research').first().json.content || ''; } catch(e) {}

// Build structured headlines array for storage (title + url + source)
const sourceMap = {};
const feeds = [
  {id: '2', name: 'Breaking Defense'},
  {id: '10', name: 'DefenseScoop'},
  {id: '12', name: 'Defense News'}
];
// headlines already parsed by Parse RSS Filter 24h with {title, link, pubDate, summary}
const headlines = (rss.items || []).map(item => ({
  title: item.title,
  url: item.link || null,
  source: item.link ? (item.link.includes('breakingdefense') ? 'Breaking Defense' : item.link.includes('defensescoop') ? 'DefenseScoop' : item.link.includes('defensenews') ? 'Defense News' : 'Defense News') : 'Defense News',
  pubDate: item.pubDate || null,
  summary: item.summary || ''
}));

const systemPrompt = `You are a defense BD intelligence analyst for Shawn Seffernick, President of Envision Innovative Solutions OU3. FY26 target $42.8M. Focus areas: Army C5ISR, IEW&S, signals intelligence, intel community IT. Produce a structured morning briefing with these exact sections:\n\n**TOP STORIES** (3 max, defense news that directly affects his pipeline or competitive landscape — 1 sentence why each matters)\n\n**SAM.GOV SIGNALS** (new solicitations/awards from the last 24h — note NAICS, agency, deadline, and pursuit recommendation YES/MAYBE/NO)\n\n**MARKET PULSE** (1-2 sentences from Perplexity research on broader defense market trends relevant to his focus)\n\nNo preamble. No filler. Every word earns its place.`;

const userContent = `=== DEFENSE NEWS (${rss.count} articles) ===\n${JSON.stringify(rss.items,null,2)}\n\n=== SAM.GOV NEW OPPS (${sam.sam_count} results) ===\n${JSON.stringify(sam.sam_opps,null,2)}\n\n=== PERPLEXITY MARKET RESEARCH ===\n${perp.slice(0,1000)}`;

return [{json:{system: systemPrompt, user: userContent, headlines_json: JSON.stringify(headlines)}}];
